def inside_image() -> bool:
    """Check if the current process is in a Bertrand image context.

    Returns
    -------
    bool
        True if we're either building an image or running inside a container process.
        False otherwise.

    Notes
    -----
    If this is true and `inside_container()` is false, then it means the CLI was
    invoked from a Containerfile during an image build, which corresponds to
    ahead-of-time (AoT) compilation for statically-typed languages.  The `build`
    command takes advantage of this to differentiate between normal (in-image) and
    editable (in-container) installs, for example.
    """
    value = os.environ.get(BERTRAND_ENV, "")
    return value == "image" or value == "container"


def inside_container() -> bool:
    """Check if we're currently running inside a Bertrand container instance.

    Returns
    -------
    bool
        True if we're running inside a container process, False otherwise.
    """
    return os.environ.get(BERTRAND_ENV, "") == "container"


@dataclass(frozen=True)
class Deadline:
    """An absolute time deadline as a unix timestamp plus a user-provided timeout.

    Attributes
    ----------
    start : float
        Unix timestamp when the deadline was created.
    timeout : float
        Seconds until the deadline expires.  Must be positive (including infinity), but
        not NaN.
    """

    timeout: float
    start: float = field(default_factory=time.time)

    def __post_init__(self) -> None:
        """Validate that the deadline has not already expired.

        Raises
        ------
        TimeoutError
            If the deadline has already expired at the time of creation.
        ValueError
            If the timeout is NaN.
        """
        if math.isnan(self.timeout):
            msg = "timeout cannot be NaN"
            raise ValueError(msg)
        if self.timeout <= 0:
            raise TimeoutError

    @property
    def stop(self) -> float:
        """Return the unix timestamp when the deadline expires.

        Returns
        -------
        float
            Unix timestamp when the deadline expires.
        """
        return self.start + self.timeout

    @property
    def remaining(self) -> float:
        """Return the remaining budget in seconds.

        Returns
        -------
        float
            Remaining time until expiration.  The value may be negative after the
            deadline has elapsed.
        """
        return self.stop - time.time()

    def check(self, msg: str = "", err: BaseException | None = None) -> float:
        """Return remaining time or raise when the deadline has elapsed.

        Parameters
        ----------
        msg : str, optional
            Error message to raise when no time remains.  Defaults to an empty string.
        err : BaseException | None, optional
            Optional inner exception to raise from when throwing a TimeoutError.

        Returns
        -------
        float
            Positive remaining budget in seconds.  This method is similar to
            `remaining`, but raises a TimeoutError with the provided message rather
            than returning a negative value when the deadline has elapsed.

        Raises
        ------
        TimeoutError
            If the deadline has elapsed.
        """
        remaining = self.remaining
        if remaining <= 0:
            raise TimeoutError(msg) from err
        return remaining

    async def call[T](
        self,
        closure: Callable[[Deadline], Awaitable[T]],
        *,
        msg: str,
        timeout: float = math.inf,
        delay: float = 0.0,
        catch: tuple[type[BaseException], ...] = (
            TimeoutError,
            subprocess.TimeoutExpired,
        ),
    ) -> T:
        """Retry an async closure until it succeeds or the deadline expires.

        Parameters
        ----------
        closure : Callable[[Deadline], Awaitable[T]]
            Async function to call with the remaining timeout budget for each attempt.
            Any returned value, including None, is treated as success.
        msg : str
            Error message to raise if the overall deadline expires before `closure`
            succeeds.
        timeout : float
            Maximum time to wait for `op` to succeed before giving up and retrying.
            Must be positive (including infinity), but not NaN.  The actual timeout
            used to run each attempt will be the minimum of this and the remaining time
            until the overall deadline expires.
        delay : float
            Number of seconds to wait between failed attempts.  A value of zero will
            yield to the event loop before retrying.
        catch : tuple[type[BaseException], ...], optional
            Exceptions to catch and retry on.  Defaults to
            `(TimeoutError, subprocess.TimeoutExpired)`.

        Returns
        -------
        T
            The value returned by `op`.

        Raises
        ------
        TimeoutError
            If the overall deadline expires before `op` succeeds.
        ValueError
            If `delay` is negative or infinite.
        """
        if delay < 0 or math.isinf(delay):
            msg = f"delay must be non-negative and finite: {delay}"
            raise ValueError(msg)

        last_error: BaseException | None = None
        while True:
            remaining = self.remaining
            if remaining <= 0:
                raise TimeoutError(msg) from last_error

            try:
                return await closure(Deadline(min(timeout, remaining)))
            except catch as err:
                last_error = err

            remaining = self.remaining
            await asyncio.sleep(min(delay, remaining))


class CompletedProcess(subprocess.CompletedProcess[str]):
    """Format completed subprocess results with command context."""

    def __str__(self) -> str:
        """Return a formatted command result.

        Returns
        -------
        str
            The formatted command result.
        """
        out = [
            f"Exit code {self.returncode} from command:\n\n"
            f"    {' '.join(shlex.quote(a) for a in self.args)}"
        ]
        if self.stderr:
            out.append(self.stderr.strip())
        return "\n\n".join(out)


class CommandError(subprocess.CalledProcessError):
    """Format failed subprocess results with command context."""

    def __str__(self) -> str:
        """Return a formatted command failure.

        Returns
        -------
        str
            The formatted command failure.
        """
        out = [
            f"Exit code {self.returncode} from command:\n\n"
            f"    {' '.join(shlex.quote(a) for a in self.cmd)}"
        ]
        if self.stderr:
            out.append(self.stderr.strip())
        return "\n\n".join(out)


class TimeoutExpired(subprocess.TimeoutExpired, TimeoutError):  # noqa: N818
    """Format subprocess timeouts as standard timeout errors."""

    def __str__(self) -> str:
        """Return a formatted subprocess timeout.

        Returns
        -------
        str
            The formatted timeout error.
        """
        out = [
            f"Command timed out after {self.timeout} seconds:\n\n"
            f"    {' '.join(shlex.quote(a) for a in self.cmd)}"
        ]
        if self.output:
            out.append(self.output.strip())
        if self.stderr:
            out.append(str(self.stderr.strip()))
        return "\n\n".join(out)


NO_DEADLINE = Deadline(timeout=math.inf)


def can_escalate() -> bool:
    """Check whether the current system supports privilege escalation.

    Returns
    -------
    bool
        True if privilege escalation is possible on the current system, false
        otherwise.
    """
    return os.name == "posix" and bool(shutil.which("sudo") or shutil.which("doas"))


def confirm(prompt: str, *, assume_yes: bool = False) -> bool:
    """Ask the user for a yes/no confirmation for a given prompt.

    Parameters
    ----------
    prompt : str
        The prompt to display to the user.
    assume_yes : bool, optional
        If True, automatically return True without prompting the user.  Default is
        False.

    Returns
    -------
    bool
        True if the user confirmed yes, false otherwise.
    """
    if assume_yes:
        return True
    try:
        response = input(prompt).strip().lower()
    except EOFError:
        return False
    return response in {"y", "yes"}


def warn(msg: str) -> None:
    """Print a Bertrand warning to standard error.

    Parameters
    ----------
    msg : str
        Warning text without the CLI prefix.
    """
    print(f"[bertrand] warning: {msg}", file=sys.stderr)


async def _run_no_capture(
    *,
    argv: list[str],
    proc: asyncio.subprocess.Process,
    stdin: str | None,
    deadline: Deadline,
) -> CompletedProcess | CommandError | TimeoutExpired | None:
    stdin_bytes = None if stdin is None else stdin.encode("utf-8", errors="replace")
    try:
        remaining = deadline.check()
        await asyncio.wait_for(
            proc.communicate(stdin_bytes),
            timeout=None if math.isinf(remaining) else remaining,
        )
    except TimeoutError:
        proc.kill()
        await proc.wait()
        return TimeoutExpired(
            cmd=argv,
            timeout=deadline.timeout,
            output=None,
            stderr=None,
        )

    if proc.returncode is None:
        proc.kill()
        await proc.wait()
        return None

    if proc.returncode == 0:
        return CompletedProcess(
            args=argv,
            returncode=proc.returncode,
            stdout=None,
            stderr=None,
        )
    return CommandError(
        returncode=proc.returncode,
        cmd=argv,
        output=None,
        stderr=None,
    )


async def _run_capture(
    *,
    argv: list[str],
    proc: asyncio.subprocess.Process,
    stdin: str | None,
    deadline: Deadline,
) -> CompletedProcess | CommandError | TimeoutExpired | None:
    stdin_bytes = None if stdin is None else stdin.encode("utf-8", errors="replace")
    try:
        remaining = deadline.check()
        stdout_raw, stderr_raw = await asyncio.wait_for(
            proc.communicate(stdin_bytes),
            timeout=None if math.isinf(remaining) else remaining,
        )
    except TimeoutError:
        proc.kill()
        stdout_raw, stderr_raw = await proc.communicate()
        return TimeoutExpired(
            cmd=argv,
            timeout=deadline.timeout,
            output=stdout_raw.decode("utf-8", errors="replace") or None,
            stderr=stderr_raw.decode("utf-8", errors="replace") or None,
        )

    if proc.returncode is None:
        proc.kill()
        await proc.wait()
        return None

    stdout_text = stdout_raw.decode("utf-8", errors="replace")
    stderr_text = stderr_raw.decode("utf-8", errors="replace")
    if proc.returncode == 0:
        return CompletedProcess(
            args=argv,
            returncode=proc.returncode,
            stdout=stdout_text,
            stderr=stderr_text,
        )
    return CommandError(
        returncode=proc.returncode,
        cmd=argv,
        output=stdout_text,
        stderr=stderr_text,
    )


async def _tee(
    src: asyncio.StreamReader | None,
    sink: TextIO,
    buf_list: list[str],
) -> None:
    if src is None:
        return
    while True:
        chunk = await src.readline()
        if not chunk:
            break
        text = chunk.decode("utf-8", errors="replace")
        buf_list.append(text)
        try:
            sink.write(text)
            sink.flush()
        except OSError:
            pass


async def _write_stdin(dst: asyncio.StreamWriter | None, data: str) -> None:
    if dst is None:
        return
    try:
        dst.write(data.encode("utf-8", errors="replace"))
        await dst.drain()
    except (BrokenPipeError, ConnectionResetError, OSError):
        pass
    finally:
        try:
            dst.close()
            await dst.wait_closed()
        except (AttributeError, RuntimeError, OSError):
            pass


async def _run_tee(
    *,
    argv: list[str],
    proc: asyncio.subprocess.Process,
    stdin: str | None,
    deadline: Deadline,
) -> CompletedProcess | CommandError | TimeoutExpired | None:
    stdout_lines: list[str] = []
    stderr_lines: list[str] = []
    tasks: list[asyncio.Task[None]] = [
        asyncio.create_task(_tee(proc.stdout, sys.stdout, stdout_lines)),
        asyncio.create_task(_tee(proc.stderr, sys.stderr, stderr_lines)),
    ]
    if stdin is not None:
        tasks.append(asyncio.create_task(_write_stdin(proc.stdin, stdin)))

    try:
        remaining = deadline.check()
        await asyncio.wait_for(
            proc.wait(),
            timeout=None if math.isinf(remaining) else remaining,
        )
    except TimeoutError:
        proc.kill()
        await proc.wait()
        stdout_text = "".join(stdout_lines)
        stderr_text = "".join(stderr_lines)
        return TimeoutExpired(
            cmd=argv,
            timeout=deadline.timeout,
            output=stdout_text or None,
            stderr=stderr_text or None,
        )
    finally:
        for task in tasks:
            await task

    if proc.returncode is None:
        proc.kill()
        await proc.wait()
        return None

    stdout_text = "".join(stdout_lines)
    stderr_text = "".join(stderr_lines)
    if proc.returncode == 0:
        return CompletedProcess(
            args=argv,
            returncode=proc.returncode,
            stdout=stdout_text,
            stderr=stderr_text
        )
    return CommandError(
        returncode=proc.returncode,
        cmd=argv,
        output=stdout_text,
        stderr=stderr_text
    )


async def run(
    argv: list[str],
    *,
    check: bool = True,
    capture_output: bool | None = False,
    input: str | None = None,  # noqa: A002
    deadline: Deadline = NO_DEADLINE,
    attempts: int = 1,
    delay: float = 0.0,
    cwd: Path | None = None,
    env: Mapping[str, str] | None = None,
) -> CompletedProcess:
    """Run an async subprocess wrapper with enhanced timeout and error ergonomics.

    Parameters
    ----------
    argv : list[str]
        The command and its arguments to run.
    check : bool, optional
        Whether to raise a `CommandError` if the command fails (default is True).  If
        false, then any errors will be ignored.
    capture_output : bool | None, optional
        If true, then all output will be redirected to the returned `CompletedProcess`
        or `CommandError`, and excluded from the inherited stdout/stderr streams.  If
        false (the default), then the opposite is the case, and the returned
        `CompletedProcess` or `CommandError` will not include any captured output.  If
        None, then output will be "tee'd" to both the console and the returned objects
        simultaneously.  Note that teeing output in this way may break TTY behavior for
        some commands, and is not recommended for interactive use.
    input : str | None, optional
        Input to send to the command's stdin (default is None).
    deadline : Deadline, optional
        An overall deadline by which the command must complete before raising a
        `TimeoutExpired` exception.  Defaults to an infinite deadline, which causes the
        command to block indefinitely until completion.  If the deadline is earlier
        than the time this method is called, then a `TimeoutExpired` exception will be
        raised immediately.
    attempts : int, optional
        The total number of times to attempt the command.  Defaults to 1, which means
        no retries.  If greater than 1, then any command that exits with a nonzero
        exit code will be re-run after a short delay, up to the specified number
        of times in total.
    delay : float, optional
        The delay in seconds to wait between retries when `attempts` is greater than 1.
        Default is zero, which yields to the event loop before retrying.  Must be
        non-negative.
    cwd : Path | None, optional
        An optional working directory to run the command in.  If None (the default),
        then the current working directory will be used.
    env : Mapping[str, str] | None, optional
        An optional environment dictionary to use for the command.  If None (the
        default), then the current process's environment will be used.

    Returns
    -------
    CompletedProcess
        The completed process result.

    Raises
    ------
    CommandError
        If the command fails and `check` is True.  If `attempts > 1`, then this will
        only reflect the last attempt, and any previous errors will be ignored.
    TimeoutExpired
        If the command does not complete within the specified timeout.
    ValueError
        If `attempts` is less than one or `delay` is negative.
    """
    if attempts < 1:
        msg = f"attempts must be at least 1: {attempts}"
        raise ValueError(msg)
    if delay < 0:
        msg = f"delay must be non-negative: {delay}"
        raise ValueError(msg)
    if deadline.remaining <= 0:
        raise TimeoutExpired(
            cmd=argv,
            timeout=deadline.timeout,
            output=None,
            stderr=None,
        )

    # loop until success, deadline is exceeded, or attempts are exhausted
    while True:
        proc = await asyncio.create_subprocess_exec(
            *argv,
            stdin=asyncio.subprocess.PIPE if input is not None else None,
            stdout=None if capture_output is False else asyncio.subprocess.PIPE,
            stderr=None if capture_output is False else asyncio.subprocess.PIPE,
            cwd=cwd,
            env=env,
        )

        # capture_output=False -> inherit terminal streams and do not capture output
        if capture_output is False:
            result = await _run_no_capture(
                argv=argv,
                proc=proc,
                stdin=input,
                deadline=deadline,
            )

        # capture_output=True -> full capture with no tee
        elif capture_output is True:
            result = await _run_capture(
                argv=argv,
                proc=proc,
                stdin=input,
                deadline=deadline,
            )

        # capture_output=None -> tee streams while capturing for return/errors
        else:
            result = await _run_tee(
                argv=argv,
                proc=proc,
                stdin=input,
                deadline=deadline,
            )
        if isinstance(result, CompletedProcess):
            return result
        if isinstance(result, TimeoutExpired):
            raise result

        attempts -= 1
        if attempts > 0:
            remaining = deadline.remaining
            if remaining <= 0:
                raise TimeoutExpired(
                    cmd=argv,
                    timeout=deadline.timeout,
                    output=result.stdout if result else None,
                    stderr=result.stderr if result else None,
                ) from result
            await asyncio.sleep(min(delay, remaining))
        elif result is not None:
            if check:
                raise result
            return CompletedProcess(
                args=argv,
                returncode=result.returncode,
                stdout=result.output,
                stderr=result.stderr,
            )
        else:
            err = (
                "unspecified error: command did not complete successfully, but no "
                "error information was captured"
            )
            if check:
                raise CommandError(returncode=-1, cmd=argv, output=None, stderr=err)
            return CompletedProcess(args=argv, returncode=-1, stdout="", stderr=err)


def sudo(argv: list[str], *, non_interactive: bool = False) -> list[str]:
    """Return a command with privilege escalation prepended when needed.

    Parameters
    ----------
    argv : list[str]
        The command and its arguments.
    non_interactive : bool, optional
        If True, add non-interactive flags for the selected escalator so it fails
        immediately instead of prompting for a password.

    Returns
    -------
    list[str]
        A new list containing either the original command (when no escalation is
        needed/available) or the escalated command.

    Notes
    -----
    Escalation is only attempted on POSIX systems for non-root users.  The selection
    order is `sudo`, then `doas`.
    """
    # no-op outside POSIX, when already root, or when no supported escalator is found
    if os.name != "posix" or os.geteuid() == 0:
        return argv.copy()
    escalator = None
    if shutil.which("sudo"):
        escalator = "sudo"
    elif shutil.which("doas"):
        escalator = "doas"
    if escalator is None:
        return argv.copy()

    out = [escalator]
    if non_interactive:
        out.append("-n")
    out.extend(argv)
    return out


@dataclass(frozen=True)
class User:
    """A simple structure representing a user identity by user ID and group ID.

    Attributes
    ----------
    uid : int
        The numeric user ID.
    gid : int
        The numeric group ID.
    name : str
        The username.
    home : Path
        The path to the user's home directory.
    """

    uid: int = field(init=False)
    gid: int = field(init=False)
    name: str = field(init=False)
    home: Path = field(init=False)

    def __post_init__(self) -> None:
        """Resolve the effective host user identity."""
        euid = os.geteuid()
        sudo_uid = os.environ.get("SUDO_UID")
        sudo_user = os.environ.get("SUDO_USER")
        if euid == 0 and sudo_uid:
            object.__setattr__(self, 'uid', int(sudo_uid))
            pw = pwd.getpwuid(self.uid)
            object.__setattr__(self, 'gid', pw.pw_gid)
            object.__setattr__(self, 'name', sudo_user or pw.pw_name)
            object.__setattr__(self, 'home', Path(pw.pw_dir))
        else:
            object.__setattr__(self, 'uid', os.getuid())
            pw = pwd.getpwuid(self.uid)
            object.__setattr__(self, 'gid', pw.pw_gid)
            object.__setattr__(self, 'name', pw.pw_name)
            object.__setattr__(self, 'home', Path(pw.pw_dir))


@dataclass(frozen=True)
class GroupStatus:
    """A simple struct representing a user's membership status in a host group.

    Attributes
    ----------
    configured : bool
        Whether the user is configured as a member of the group (either as a primary or
        secondary member).
    active : bool
        Whether the user's current session is active in the group (i.e. whether the
        group is included in the user's current group list, which is determined at
        login and may need to be refreshed via `newgrp` or a logout/login cycle).
    """

    user: str
    group: str
    configured: bool
    active: bool

    @classmethod
    def get(cls, user: str, group: str) -> Self:
        """Return (configured, active) for user membership in a host group.

        Parameters
        ----------
        user : str
            The username to check for.
        group : str
            The group name to check against.

        Returns
        -------
        GroupStatus
            A GroupStatus object representing the user's membership status.
        """
        try:
            group_info = grp.getgrnam(group)
        except KeyError:
            return cls(user=user, group=group, configured=False, active=False)
        try:
            primary_gid = pwd.getpwnam(user).pw_gid
        except KeyError:
            primary_gid = None
        configured = user in group_info.gr_mem or primary_gid == group_info.gr_gid
        active = (
            group_info.gr_gid in os.getgroups() or os.getegid() == group_info.gr_gid
        )
        return cls(user=user, group=group, configured=configured, active=active)

    async def activate(self, *, assume_yes: bool) -> None:
        """Ensure host group membership.

        Parameters
        ----------
        assume_yes : bool
            If True, automatically confirm any prompts for fixing group membership.

        Raises
        ------
        PermissionError
            If the user declines to update their group membership, or if the update
            requires root privileges and they are not available.
        OSError
            If group membership still isn't properly configured after attempting to
            update it.
        """
        status = self
        if status.configured and status.active:
            return

        # ensure membership
        if not status.configured:
            if not confirm(
                f"Bertrand must add user {status.user!r} to the {status.group!r} "
                f"group in order to avoid future root escalation.  Would you like "
                "Bertrand to add this membership now (requires sudo)?\n[y/N] ",
                assume_yes=assume_yes,
            ):
                msg = f"{status.group} group membership update declined by user."
                raise PermissionError(msg)
            if os.geteuid() != 0 and not can_escalate():
                msg = (
                    f"Updating {status.group} group membership requires root "
                    "privileges; "
                    "sudo not available."
                )
                raise PermissionError(msg)
            await run(
                sudo(
                    ["usermod", "-a", "-G", status.group, status.user],
                    non_interactive=assume_yes,
                )
            )
            status = GroupStatus.get(status.user, status.group)
            if not status.configured:
                msg = f"failed to add user '{status.user}' to group '{status.group}'"
                raise OSError(msg)

        # warn if group membership is not active in current session
        if not status.active:
            warn(
                f"added {status.user!r} to the {status.group!r} group, but "
                "sudo is still required for this session.  Run "
                f"`newgrp {status.group}` "
                "or log out and back in to pick up the new group privileges before "
                "proceeding."
            )


