async def install_packages(
    package_manager: str,
    packages: Sequence[str],
    *,
    deadline: Deadline = NO_DEADLINE,
    yes: bool = False,
) -> None:
    """Install OS packages with the requested host package manager.

    Parameters
    ----------
    package_manager : str
        The package manager to use (e.g. "apt", "dnf", etc.).
    packages : Sequence[str]
        The packages to install.
    deadline : Deadline, optional
        An overall deadline by which the installation must complete before raising a
        `TimeoutExpired` exception.  Defaults to an infinite deadline, which causes the
        command to block indefinitely until completion.  If the deadline is earlier than
        the time this method is called, a `TimeoutExpired` exception will be raised
        immediately.
    yes : bool, optional
        If True, automatically confirm any prompts for installation or refreshing
        package lists.  Default is False.

    Raises
    ------
    OSError
        If the package manager is not supported on the current system.
    PermissionError
        If the package manager requires root privileges and they are not available.
    ValueError
        If the specified package manager is not supported.
    FileNotFoundError
        If the package manager's executable or its refresh command (if applicable) is
        not found in the system PATH.
    """
    if os.name != "posix":
        msg = "package manager operations require a POSIX system."
        raise OSError(msg)
    if os.geteuid() != 0 and not can_escalate():
        msg = (
            f"package installation using {package_manager!r} requires root "
            "privileges; sudo not available."
        )
        raise PermissionError(msg)

    # get package manager spec
    spec = _INSTALL_SPECS.get(package_manager)
    if spec is None:
        msg = (
            f"unsupported package manager {package_manager!r} (supported: "
            f"{sorted(_INSTALL_SPECS)})"
        )
        raise ValueError(msg)
    if not shutil.which(spec.install[0]):
        msg = f"package manager {package_manager!r} not found: {spec.install[0]}"
        raise FileNotFoundError(msg)
    if spec.refresh is not None and not shutil.which(spec.refresh[0]):
        msg = f"refresh command not found: {spec.refresh[0]}"
        raise FileNotFoundError(msg)

    # generate environment for non-interactive installs, if needed
    env: dict[str, str] | None = None
    if yes and spec.noninteractive_env:
        env = os.environ.copy()
        env.update(spec.noninteractive_env)

    # refresh package lists if supported
    if spec.refresh is not None:
        cmd = spec.refresh.copy()
        if yes:
            cmd.extend(spec.yes_refresh)
        await run(
            sudo(cmd, non_interactive=yes),
            env=env,
            deadline=deadline,
        )

    # install requested packages
    cmd = spec.install.copy()
    if yes:
        cmd.extend(spec.yes_install)
    cmd.extend(packages)
    await run(
        sudo(cmd, non_interactive=yes),
        env=env,
        deadline=deadline,
    )


def abspath(path: Path) -> Path:
    """Normalize a filesystem path without resolving symlinks.

    Parameters
    ----------
    path : Path
        The path to normalize.

    Returns
    -------
    Path
        The normalized path.
    """
    return Path(os.path.abspath(path.expanduser()))  # noqa: PTH100


def symlink_points_to(path: Path, target: Path) -> bool:
    """Return whether `path` is a symlink to `target`.

    Parameters
    ----------
    path : Path
        Candidate alias path.
    target : Path
        Expected hidden mount destination.

    Returns
    -------
    bool
        True when `path` is a symlink whose raw target is absolute and exactly
        equal to `target`.
    """
    try:
        if path.is_symlink():
            current = path.readlink()
            return current.is_absolute() and current == target
    except OSError:
        pass
    return False


def atomic_symlink(source: Path, target: Path, *, private: bool = False) -> None:
    """Atomically create a symbolic link, avoiding race conditions and partial writes.

    Parameters
    ----------
    source : Path
        The source path the symbolic link should point to.
    target : Path
        The target path of the symbolic link to create.
    private : bool, optional
        Whether to set private permissions (0600) on the created symlink, by default
        False.
    """
    target.parent.mkdir(parents=True, exist_ok=True)
    tmp = target.with_name(f"{target.name}.tmp.{uuid.uuid4().hex}")
    tmp.symlink_to(source)
    if private:
        tmp.chmod(0o600)
    tmp.replace(target)


def atomic_write_text(
    path: Path,
    text: str,
    encoding: str | None = None,
    *,
    private: bool = False,
) -> None:
    """Atomically write text to a file, avoiding race conditions and partial writes.

    Parameters
    ----------
    path : Path
        The path to write to.
    text : str
        The text to write.
    encoding : str | None, optional
        The text encoding to use (default is None, which uses the system default).
    private : bool, optional
        Whether to set private permissions (0600) on the written file, by default False.
    """
    path.parent.mkdir(parents=True, exist_ok=True)
    tmp = path.with_name(f"{path.name}.tmp.{uuid.uuid4().hex}")
    tmp.write_text(text, encoding=encoding)
    with tmp.open("r+", encoding=encoding) as f:
        f.flush()
        os.fsync(f.fileno())
    if private:
        tmp.chmod(0o600)
    tmp.replace(path)


# TODO: try to delete the privileges field for the lock file.  I could maybe just
# use o660 for the lock file, which would extend rw access to the `bertrand` user group,
# as long as I then create all lock files under that group.

# -> Use `os.fchown` and always create the lock file under the `bertrand` group, if it
# exists, or possibly just allow everyone rwx access by default?


class HostLock:
    """A re-entrant, OS-level, asynchronous file lock."""

    path: Path
    privileges: int
    _key: tuple[str, int]
    _fd: int | None
    _owner: asyncio.Task[Any] | None
    _depth: int

    def __new__(cls, path: Path, *, privileges: int = LOCK_DEFAULT_PRIVILEGES) -> Self:
        """Construct or return a shared lock instance for the given path.

        Parameters
        ----------
        path : Path
            Local file path used for host-level locking.
        privileges : int
            The file mode to apply when creating the lock file. Defaults to `0o600`.

        Raises
        ------
        ValueError
            If `privileges` is not a valid file mode.
        OSError
            If the lock path is invalid.
        """
        path = path.expanduser().resolve()
        if privileges < 0 or privileges > 0o777:
            msg = f"invalid host lock file mode: {oct(privileges)}"
            raise ValueError(msg)
        if path.exists() and path.is_dir():
            msg = (
                f"host lock path must be a file, but a directory already exists: {path}"
            )
            raise OSError(msg)

        # allow re-entrancy with unique lock instances per owning task
        with LOCK_GUARD:
            key = (str(path), privileges)
            self = HOST_LOCKS.get(key)
            if self is None:
                self = super().__new__(cls)
                self.path = path
                self.privileges = privileges
                self._key = key
                self._fd = None
                self._owner = None
                self._depth = 0
                HOST_LOCKS[key] = self
        return cast("Self", self)

    @staticmethod
    def _get_owner() -> asyncio.Task[Any]:
        try:
            task = asyncio.current_task()
        except RuntimeError:
            task = None
        if task is None:
            msg = "HostLock requires an active asyncio Task"
            raise RuntimeError(msg)
        return task

    def _clear_owner(
        self,
        *,
        owner: asyncio.Task[Any] | None = None,
        unregister: bool = False,
    ) -> None:
        with LOCK_GUARD:
            if owner is not None and self._owner != owner:
                return
            self._owner = None
            self._depth = 0
            if unregister:
                HOST_LOCKS.pop(self._key, None)

    async def _try_acquire_file(self) -> bool:
        self.path.parent.mkdir(parents=True, exist_ok=True)
        if self._fd is None:
            self._fd = os.open(self.path, os.O_RDWR | os.O_CREAT, self.privileges)
            if hasattr(os, "fchmod"):
                with contextlib.suppress(OSError):
                    os.fchmod(self._fd, self.privileges)

        # Windows file lock on a 1-byte region
        if os.name == "nt":
            os.lseek(self._fd, 0, os.SEEK_SET)
            if os.fstat(self._fd).st_size < 1:
                os.write(self._fd, b"\0")
            try:
                msvcrt.locking(self._fd, msvcrt.LK_NBLCK, 1)
            except OSError as err:
                if err.errno in (errno.EACCES, errno.EDEADLK) or getattr(
                    err, "winerror", None
                ) in {33, 36}:
                    return False
                raise
            return True

        # POSIX non-blocking file lock
        try:
            fcntl.flock(self._fd, fcntl.LOCK_EX | fcntl.LOCK_NB)
        except BlockingIOError:
            return False
        except OSError as err:
            if err.errno in (errno.EACCES, errno.EAGAIN):
                return False
            raise
        return True

    async def _acquire_file(self, deadline: Deadline) -> bool:
        while not await self._try_acquire_file():
            remaining = deadline.remaining
            if remaining <= 0:
                return False
            await asyncio.sleep(min(SHORT_DELAY, remaining))
        return True

    async def _release_file(self) -> None:
        if self._fd is None:
            return
        fd = self._fd
        self._fd = None
        try:
            if os.name == "nt":
                os.lseek(fd, 0, os.SEEK_SET)
                with contextlib.suppress(OSError):
                    msvcrt.locking(fd, msvcrt.LK_UNLCK, 1)
            else:
                with contextlib.suppress(OSError):
                    fcntl.flock(fd, fcntl.LOCK_UN)
        finally:
            os.close(fd)
            with contextlib.suppress(OSError):
                self.path.unlink()

    async def lock(self, deadline: Deadline) -> Self:
        """Acquire this file lock, waiting for this lock's timeout if needed.

        Parameters
        ----------
        deadline : Deadline
            The deadline by which the lock must be acquired before raising a
            `TimeoutError`.

        Returns
        -------
        Self
            This lock instance after acquisition.

        Raises
        ------
        TimeoutError
            If the lock cannot be acquired before its timeout.
        OSError
            If the lock file cannot be created, locked, or cleaned up after a failed
            acquisition.
        """
        owner = self._get_owner()

        # fast-path: same task re-entrancy
        while True:
            with LOCK_GUARD:
                if self._owner is None:
                    self._owner = owner
                    self._depth = 1
                    break
                if self._owner == owner:
                    self._depth += 1
                    return self
            if deadline.remaining <= 0:
                msg = (
                    f"could not acquire lock at {self.path} within {deadline.timeout} "
                    "seconds"
                )
                raise TimeoutError(msg)
            await asyncio.sleep(min(deadline.remaining, SHORT_DELAY))

        # slow path: acquire via backend
        try:
            if not await self._acquire_file(deadline):
                msg = f"could not acquire lock within {deadline.timeout} seconds"
                raise TimeoutError(msg)
        except OSError:
            with contextlib.suppress(OSError):
                await self._release_file()
            self._clear_owner(owner=owner)
            raise

        return self

    async def try_lock(self) -> bool:
        """Attempt to acquire this lock immediately, without waiting on contention.

        Returns
        -------
        bool
            `True` if the lock was successfully acquired, or `False` if the lock is
            currently held by another task or process.

        Raises
        ------
        OSError
            If the lock file cannot be created, locked, or cleaned up after a failed
            acquisition.
        """
        owner = self._get_owner()

        # fast-paths: re-entrant success or immediate contention failure
        with LOCK_GUARD:
            if self._owner == owner:
                self._depth += 1
                return True
            if self._owner is not None:
                return False
            self._owner = owner
            self._depth = 1

        # slow path: single backend attempt only
        try:
            acquired = await self._try_acquire_file()
        except OSError:
            with contextlib.suppress(OSError):
                await self._release_file()
            self._clear_owner(owner=owner)
            raise

        if acquired:
            return True

        self._clear_owner(owner=owner)
        return False

    async def unlock(self, *, ignore_errors: bool = False) -> None:
        """Release this lock once.  Re-entrant lock depth is decremented.

        Parameters
        ----------
        ignore_errors : bool
            If `True`, suppress any exceptions raised by the backend release operation,
            which may be desirable if the lock is being released in response to an
            error condition and the caller wishes to preserve the original exception.
            Defaults to `False`, in which case backend errors will be raised after
            releasing the lock and clearing lock state.

        Raises
        ------
        RuntimeError
            If the current task does not hold this lock.
        OSError
            If the lock file cannot be released and `ignore_errors` is `False`.
        """
        owner = self._get_owner()
        with LOCK_GUARD:
            if self._owner != owner or self._depth < 1:
                msg = "lock is not held by the current owner"
                raise RuntimeError(msg)
            self._depth -= 1
            if self._depth > 0:
                return  # re-entrant case

        try:
            await self._release_file()
        except OSError:
            if not ignore_errors:
                raise
        finally:
            self._clear_owner(unregister=True)

    def __bool__(self) -> bool:
        """Return whether this lock is currently held by any task or process.

        Returns
        -------
        bool
            `True` if this lock is currently held by any task or process, or `False
            if this lock is currently free.
        """
        with LOCK_GUARD:
            return self._depth > 0

    def __repr__(self) -> str:
        """Return a string representation of this lock.

        Returns
        -------
        str
            A string representation of this lock.
        """
        return f"HostLock(path={self.path!r})"


_HOOK_OPERATION_ERRORS: tuple[type[Exception], ...] = (
    OSError,
    RuntimeError,
    TimeoutError,
    ValueError,
    CommandError,
)


@dataclass(frozen=True)
class GitRefUpdate:
    """A single reference update received from git on stdin."""

    old: str
    new: str
    ref: str

    @property
    def is_head(self) -> bool:
        """Return whether this update targets a branch ref.

        Returns
        -------
        bool
            True if this update targets `refs/heads/*`.
        """
        return self.ref.startswith(GIT_REF_HEADS_PREFIX)

    @property
    def branch(self) -> str:
        """Return the short branch name for this update.

        Returns
        -------
        str
            The short branch name for `refs/heads/*` updates.
        """
        return self.ref[len(GIT_REF_HEADS_PREFIX) :]

    @property
    def created(self) -> bool:
        """Return whether this update created a ref.

        Returns
        -------
        bool
            True if this update created a new ref.
        """
        return all(c == "0" for c in self.old) and any(c != "0" for c in self.new)

    @property
    def destroyed(self) -> bool:
        """Return whether this update deleted a ref.

        Returns
        -------
        bool
            True if this update deleted an existing ref.
        """
        return any(c != "0" for c in self.old) and all(c == "0" for c in self.new)

    @classmethod
    def parse(cls, stdin: str) -> list[GitRefUpdate]:
        """Parse and validate transaction update lines from stdin.

        Parameters
        ----------
        stdin : str
            The raw stdin input containing reference update lines, typically read from
            the `reference-transaction` hook's standard input stream.

        Returns
        -------
        list[GitRefUpdate]
            A list of parsed reference updates.

        Raises
        ------
        ValueError
            If any line is malformed.
        """
        updates: list[GitRefUpdate] = []
        for index, raw in enumerate(stdin.splitlines(), start=1):
            line = raw.strip()
            if not line:
                continue
            parts = line.split()
            if len(parts) != 3:
                msg = (
                    f"malformed git transaction line {index}: expected "
                    f"'<old> <new> <ref>', got: {raw!r}"
                )
                raise ValueError(msg)
            old, new, ref = (part.strip() for part in parts)
            if not ref:
                msg = f"malformed git transaction line {index}: ref must not be empty"
                raise ValueError(msg)
            updates.append(cls(old=old, new=new, ref=ref))
        return updates


@dataclass(frozen=True)
class GitRepository:
    """An object-oriented wrapper around a Git repository.

    Attributes
    ----------
    git_dir : Path, optional
        The path to the repository's .git directory.  If omitted, the repository will
        be by running `git rev-parse --git-common-dir` in the current working
        directory.
    """

    @dataclass(frozen=True)
    class Worktree:
        """A parsed entry from `git worktree list --porcelain`.

        Attributes
        ----------
        path : Path
            The absolute path to the worktree checkout.
        branch : str | None
            The short branch name if this worktree is attached to `refs/heads/*`,
            otherwise None.
        """

        repo: GitRepository
        path: Path
        branch: str | None = None

        @property
        def id(self) -> str:
            """Ensure a checked-out worktree has a stable Bertrand UUID.

            Returns
            -------
            str
                Existing or newly generated UUID hex string.

            Raises
            ------
            FileNotFoundError
                If the worktree path does not exist.
            NotADirectoryError
                If the worktree path is not a directory.
            OSError
                If the worktree ID file exists, but is not a UTF-8 text file containing
                a valid UUID hex.
            """
            if not self.path.exists():
                msg = f"worktree path does not exist: {self.path}"
                raise FileNotFoundError(msg)
            if not self.path.is_dir():
                msg = f"worktree path is not a directory: {self.path}"
                raise NotADirectoryError(msg)

            # read an existing worktree ID if possible
            path = self.path / METADATA_ID
            if path.exists():
                if not path.is_file():
                    msg = f"Bertrand worktree identity path is not a file: {path}"
                    raise OSError(msg)
                text = path.read_text(encoding="utf-8").strip()
                return uuid.UUID(text).hex

            # generate a new worktree ID and write it atomically
            worktree_id = uuid.uuid4().hex
            atomic_write_text(path, f"{worktree_id}\n", encoding="utf-8")
            return worktree_id

        def __post_init__(self) -> None:
            """Canonicalize the worktree path and validate it exists as a directory.

            Raises
            ------
            FileNotFoundError
                If the worktree path does not exist.
            NotADirectoryError
                If the worktree path is not a directory.
            """
            object.__setattr__(self, "path", self.path.expanduser().resolve())
            if not self.path.exists():
                msg = f"worktree path does not exist: {self.path}"
                raise FileNotFoundError(msg)
            if not self.path.is_dir():
                msg = f"worktree path is not a directory: {self.path}"
                raise NotADirectoryError(msg)

        def _clean_worktree_parents(self) -> None:
            # clean up now-empty parent directories up to project root to account for
            # branch names that contain path separators
            cursor = self.path.parent
            while cursor != self.repo.root:
                try:
                    if any(cursor.iterdir()):
                        break
                    cursor.rmdir()
                except OSError:
                    break
                cursor = cursor.parent

        async def _worktree_belongs_to_repo(
            self,
            *,
            env: dict[str, str],
            deadline: Deadline
        ) -> bool:
            result = await run(
                ["git", "-C", str(self.path), "rev-parse", "--git-common-dir"],
                check=False,
                capture_output=True,
                env=env,
                deadline=deadline
            )
            if result.returncode != 0:
                return False
            owner = Path(result.stdout.strip()).expanduser()
            if not owner.is_absolute():
                owner = self.path / owner
            return self.repo.git_dir == owner.expanduser().resolve()

        async def move(
            self,
            target: Path | None = None,
            *,
            deadline: Deadline = NO_DEADLINE,
        ) -> None:
            """Move this worktree to a different location.

            Parameters
            ----------
            target : Path | None, optional
                The destination path for the worktree.  If None, the worktree will be
                moved to its default location based on the branch name, if it is not
                already there.  Defaults to None.
            deadline : Deadline, optional
                An overall deadline by which the move must complete before raising a
                `TimeoutError`.  Defaults to an infinite deadline, which causes the
                command to block indefinitely until completion.  If the deadline is
                earlier than the time this method is called, a `TimeoutError` will be
                raised immediately.

            Raises
            ------
            ValueError
                If the target path cannot be determined for a branchless worktree, or
                if the target path is the same as the current path.
            FileExistsError
                If the target path already exists, and is not the same as the source
                path.
            """
            if target is None:
                if self.branch is None:
                    msg = (
                        "cannot determine default worktree target path for branchless "
                        "worktree; specify an explicit target path to move this "
                        "worktree"
                    )
                    raise ValueError(msg)
                target = self.repo.root / self.branch
            if target == self.path:
                return
            if target.exists():
                msg = f"target path already exists: {target}"
                raise FileExistsError(msg)

            target.parent.mkdir(parents=True, exist_ok=True)
            await self.repo.run(
                ["worktree", "move", "--relative-paths", str(self.path), str(target)],
                capture_output=True,
                deadline=deadline,
            )
            self._clean_worktree_parents()
            object.__setattr__(self, "path", target)

        async def destroy(self, *, deadline: Deadline = NO_DEADLINE) -> bool:
            """Destroy this worktree if it exists and is clean.

            Parameters
            ----------
            deadline : Deadline, optional
                An overall deadline by which the destruction must complete before
                raising a `TimeoutError`.  Defaults to an infinite deadline, which
                causes the command to block indefinitely until completion.  If the
                deadline is earlier than the time this method is called, a
                `TimeoutError` will be raised immediately.

            Returns
            -------
            bool
                True if the worktree was successfully destroyed or did not exist, false
                if the worktree exists but could not be destroyed due to dirty state.

            Raises
            ------
            RuntimeError
                If the target path does not belong to this repository.
            """
            # verify that the worktree is clean and objectively belongs to this
            # repository before attempting deletion
            env = await self.repo._strip_env(deadline=deadline)
            if not await self._worktree_belongs_to_repo(env=env, deadline=deadline):
                msg = f"worktree path does not belong to this repository: {self.path}"
                raise RuntimeError(msg)
            clean = await run(
                ["git", "-C", str(self.path), "status", "--porcelain"],
                capture_output=True,
                env=env,
                deadline=deadline,
            )
            if clean.stdout.strip():
                return False

            # remove the worktree using git, which will also properly clean up the
            # associated gitdir and any linked metadata
            await self.repo.run(
                ["worktree", "remove", str(self.path)],
                capture_output=True,
                deadline=deadline,
            )
            self._clean_worktree_parents()
            return True

    git_dir: Path

    @property
    def root(self) -> Path:
        """Return the repository root.

        Returns
        -------
        Path
            The absolute path to the repository's root directory, which is the parent of
            the .git directory.
        """
        return self.git_dir.parent

    @property
    def id(self) -> str:
        """Return the stable Bertrand repository identity.

        Returns
        -------
        str
            Stable UUID hex string used to scope cluster resources for the repository.

        Raises
        ------
        OSError
            If Bertrand's host identity is missing or malformed. Run `bertrand init`
            to converge host state before resolving unmanaged repository identities.

        Notes
        -----
        Managed repository metadata takes precedence when present. Otherwise, the ID
        is deterministically derived from the Bertrand host identity and repository
        root path so uninitialized repositories can still address cluster resources
        consistently without colliding with matching paths on other hosts.
        """
        id_file = self.root / METADATA_ID
        if id_file.is_file():
            try:
                return uuid.UUID(id_file.read_text(encoding="utf-8").strip()).hex
            except (OSError, ValueError):
                pass
        try:
            host_id = uuid.UUID(HOST_ID_FILE.read_text(encoding="utf-8").strip())
        except (OSError, ValueError) as err:
            msg = (
                "Bertrand host identity is missing or malformed. Run `bertrand init` "
                "to converge host state before resolving unmanaged repository IDs."
            )
            raise OSError(msg) from err
        return uuid.uuid5(host_id, self.root.as_posix()).hex

    def __post_init__(self) -> None:
        """Automatically canonicalize the git_dir path."""
        object.__setattr__(self, "git_dir", self.git_dir.expanduser().resolve())

    @classmethod
    async def discover(
        cls,
        path: Path | None = None,
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> GitRepository | None:
        """Discover the Git repository for the current working directory.

        Parameters
        ----------
        path : Path | None, optional
            An optional path to use as the starting point for discovery.  If None (the
            default), then the current working directory will be used instead.
        deadline : Deadline, optional
            An overall deadline by which the discovery must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        GitRepository | None
            The discovered Git repository, assuming a `path` is inside a Git repository
        """
        result = await run(
            ["git", "rev-parse", "--path-format=absolute", "--git-common-dir"],
            cwd=path,
            check=False,
            capture_output=True,
            deadline=deadline,
        )
        if result.returncode == 0:
            return cls(git_dir=Path(result.stdout.strip()))
        return None

    @classmethod
    async def resolve(
        cls,
        path: Path,
        *,
        deadline: Deadline = NO_DEADLINE
    ) -> tuple[GitRepository, Path]:
        """Resolve a repository and worktree path.

        Parameters
        ----------
        path : Path
            The input path to resolve a repository and worktree for.  The ancestors
            will be scanned to find the nearest git repository, and the remaining path
            components will be treated as a relative worktree path within the
            repository.  If no repository is found, then the input path will be
            treated as an uninitialized repository, and the worktree will be "."
            (repository-level targeting).  If the path leads to a bare repository,
            then non-root targets must match a registered worktree root exactly.
        deadline : Deadline, optional
            An overall deadline by which the resolution must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        tuple[GitRepository, Path]
            A tuple containing the resolved Git repository and the relative worktree
            path within it.  The worktree path is "." for repository-level targets,
            and a non-empty relative path only for explicit worktree targets.  Note
            that the `GitRepository` may be uninitialized if no existing repository
            was found during resolution.

        Raises
        ------
        OSError
            If the resolved repository is bare and does not support relative paths,
            or if a non-root target is not registered as a worktree of the resolved
            repository.
        """
        repo = await cls.discover(path, deadline=deadline)

        # new bare repository
        if repo is None:
            if not await cls.supports_relative_paths(deadline=deadline):
                raise OSError(GIT_REQUIRE_RELATIVE_PATHS)
            repo = cls(path / ".git")
            return repo, Path()

        # existing bare repository
        if await repo.bare():
            if not await cls.supports_relative_paths(deadline=deadline):
                raise OSError(GIT_REQUIRE_RELATIVE_PATHS)
            worktree = path.relative_to(repo.root)
            if not worktree.parts:
                return repo, Path()
            if not any(
                wt.path == path for wt in await repo.worktrees(deadline=deadline)
            ):
                msg = (
                    f"worktree at {worktree} is not registered as a git worktree of "
                    f"bare repository: {repo.root}"
                )
                raise OSError(msg)
            return repo, worktree

        # existing non-bare repository
        worktree = path.relative_to(repo.root)
        if worktree.parts and not any(
            wt.path == path for wt in await repo.worktrees(deadline=deadline)
        ):
            msg = (
                f"nested worktree at {worktree} is not registered as a git worktree "
                f"of non-bare repository: {repo.root}"
            )
            raise OSError(msg)
        return repo, worktree

    # TODO: remove `__bool__` once the deprecation cut-over is complete

    def __bool__(self) -> NoReturn:
        """Deprecate old-style truthiness checks on GitRepository instances."""
        msg = "use explicit `GitRepository.exists()` instead of a truth check"
        raise NotImplementedError(msg)

    def __hash__(self) -> int:
        """Allow GitRepositories to be hashed according to their logical identity.

        Returns
        -------
        int
            A hash derived from the repository's `id`, which will be regenerated if it
            is missing.
        """
        return hash(self.id)

    def __eq__(self, other: object) -> bool:
        """Compare GitRepositories based on their logical identity.

        Returns
        -------
        bool | NotImplemented
            True if `other` is a GitRepository with the same `id` as this one, or
            NotImplemented if `other` is not a GitRepository.  If either repository's
            `id` is missing, it will be regenerated.
        """
        if isinstance(other, GitRepository):
            return self.id == other.id
        return NotImplemented

    async def _strip_env(self, *, deadline: Deadline) -> dict[str, str]:
        env = os.environ.copy()
        local = await self.run(
            ["rev-parse", "--local-env-vars"],
            check=False,
            capture_output=True,
            env=env,
            deadline=deadline,
        )
        if local.returncode == 0:
            keys = [key.strip() for key in local.stdout.splitlines() if key.strip()]
        else:
            keys = [
                "GIT_DIR",
                "GIT_WORK_TREE",
                "GIT_COMMON_DIR",
            ]  # best-effort fallback
        for key in keys:
            env.pop(key, None)
        return env

    async def exists(self, *, deadline: Deadline = NO_DEADLINE) -> bool:
        """Return whether this repository is a valid, initialized repository.

        Parameters
        ----------
        deadline : Deadline, optional
            An overall deadline by which the validation must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        bool
            True if this repository has been initialized, or False if it has not.
        """
        return (
            self.git_dir.exists()
            and self.git_dir.is_dir()
            and (await self.run(
                ["rev-parse", "--git-dir"],
                check=False,
                capture_output=True,
                deadline=deadline,
            )).returncode == 0
        )

    async def init(
        self,
        *,
        branch: str | None = None,
        bare: bool = True,
        deadline: Deadline = NO_DEADLINE,
    ) -> None:
        """Initialize a new Git repository at the given path.

        Parameters
        ----------
        branch : str | None, optional
            An optional initial branch name to use for the repository.  If None (the
            default), then the Git installation's default branch will be used (e.g.
            "master" or "main").
        bare : bool, optional
            Whether to create a bare repository (default is True).  If false, then a
            standard repository with a working tree will be created instead.
        deadline : Deadline, optional
            An overall deadline by which the initialization must complete before raising
            a `TimeoutError`.  Defaults to an infinite deadline, which causes the
            command to block indefinitely until completion.  If the deadline is earlier
            than the time this method is called, a `TimeoutError` will be raised
            immediately.
        """
        self.git_dir.mkdir(parents=True, exist_ok=True)
        cmd = ["git", "init", "--quiet"]
        if branch is not None:
            cmd.extend(["--initial-branch", branch])
        if bare:
            cmd.append("--bare")
        cmd.append(str(self.git_dir))
        await run(cmd, deadline=deadline)

    async def mirror_from(
        self,
        source: GitRepository,
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> None:
        """Converge this repository from a source using mirror semantics.

        This is a repository-convergence helper, not a generic clone API. It performs
        first-time mirror initialization when the destination is uninitialized, and
        subsequent full-ref mirror updates on reruns.

        Parameters
        ----------
        source : GitRepository
            Source repository whose refs/object graph should be mirrored.
        deadline : Deadline, optional
            An overall deadline by which the operation must complete before raising
            a `TimeoutError`.  Defaults to an infinite deadline, which causes the
            command to block indefinitely until completion.  If the deadline is earlier
            than the time this method is called, a `TimeoutError` will be raised
            immediately.

        Raises
        ------
        OSError
            If the source repository has not been initialized.
        """
        if not await source.exists():
            msg = (
                f"cannot mirror from uninitialized source repository: {source.git_dir}"
            )
            raise OSError(msg)

        # if this is a fresh repository, just clone directly to initialize it
        if not await self.exists():
            await run(
                [
                    "git",
                    "clone",
                    "--mirror",
                    str(source.root),
                    str(self.git_dir),
                ],
                capture_output=True,
                deadline=deadline,
            )

        # otherwise, fetch and mirror all refs to converge with the source repository
        else:
            await self.run(
                [
                    "fetch",
                    "--prune",
                    str(source.root),
                    "+refs/*:refs/*",
                ],
                capture_output=True,
                deadline=deadline,
            )

    async def run(
        self,
        argv: list[str],
        *,
        check: bool = True,
        capture_output: bool | None = False,
        input: str | None = None,  # noqa: A002
        deadline: Deadline = NO_DEADLINE,
        attempts: int = 1,
        delay: float = 0.0,
        cwd: Path | None = None,
        env: Mapping[str, str] | None = None,
    ) -> CompletedProcess:
        """Run a asynchronous git command against this repository.

        Parameters
        ----------
        argv : list[str]
            The command and its arguments to run, excluding the initial "git".
        check : bool, optional
            Whether to raise a `CommandError` if the command fails (default is True).
            If false, then any errors will be ignored.
        capture_output : bool | None, optional
            If true, then all output will be redirected to the returned
            `CompletedProcess` or `CommandError`, and excluded from the inherited
            stdout/stderr streams.  If false (the default), then the opposite is the
            case, and the returned `CompletedProcess` or `CommandError` will not
            include any captured output.  If None, then output will be "tee'd" to both
            the console and the returned objects simultaneously.  Note that teeing
            output in this way may break TTY behavior for some commands, and is not
            recommended for interactive use.
        input : str | None, optional
            Input to send to the command's stdin (default is None).
        deadline : Deadline, optional
            An overall deadline by which the command must complete before raising a
            `TimeoutExpired` exception.  Defaults to an infinite deadline, which causes
            the command to block indefinitely until completion.  If the deadline is
            earlier than the time this method is called, then a `TimeoutExpired`
            exception will be raised immediately.
        attempts : int, optional
            The total number of times to attempt the command.  Defaults to 1, which
            means no retries.  If greater than 1, then any command that exits with a
            nonzero exit code will be re-run after a short delay, up to the specified
            number of times in total.
        delay : float, optional
            The delay in seconds to wait between retries when `attempts` is greater than
            1.  Default is zero, which yields to the event loop before retrying.  Must
            be non-negative.
        cwd : Path | None, optional
            An optional working directory to run the command in.  If None (the default),
            then the current working directory will be used.
        env : Mapping[str, str] | None, optional
            An optional environment dictionary to use for the command.  If None (the
            default), then the current process's environment will be used.

        Returns
        -------
        CompletedProcess
            The completed process result.
        """
        return await run(
            ["git", "--git-dir", str(self.git_dir), *argv],
            check=check,
            capture_output=capture_output,
            input=input,
            deadline=deadline,
            attempts=attempts,
            delay=delay,
            cwd=cwd,
            env=env,
        )

    async def dirty(self, *, deadline: Deadline = NO_DEADLINE) -> bool:
        """Check whether this repository has uncommitted changes.

        Parameters
        ----------
        deadline : Deadline, optional
            An overall deadline by which the check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        bool
            `True` if any checked-out worktree for this repository has uncommitted
            changes, or `False` otherwise. Non-bare repositories are checked directly
            at `self.root`. Bare repositories are checked by scanning every registered
            worktree. Bare repositories with zero worktrees are considered clean.

        """
        if not await self.bare():
            result = await self.run(
                ["status", "--porcelain"],
                capture_output=True,
                cwd=self.root,
                deadline=deadline,
            )
            return bool(result.stdout.strip())

        # Bare repositories do not have their own worktree; check each attached
        # worktree under a sanitized git environment instead.
        env = await self._strip_env(deadline=deadline)
        for wt in await self.worktrees():
            result = await run(
                ["git", "-C", str(wt.path), "status", "--porcelain"],
                capture_output=True,
                env=env,
                deadline=deadline,
            )
            if result.stdout.strip():
                return True
        return False

    async def git_path(
        self,
        path: Path,
        *,
        cwd: Path | None = None,
        deadline: Deadline = NO_DEADLINE,
    ) -> Path:
        """Resolve a git-path using `git rev-parse --git-path`.

        Parameters
        ----------
        path : str
            The git-path expression to resolve (e.g. `hooks/pre-commit`).
        cwd : Path | None, optional
            Optional working directory for relative path resolution semantics.
        deadline : Deadline
            An overall deadline by which the resolution must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        Path
            The resolved absolute filesystem path.

        Raises
        ------
        ValueError
            If git returned an empty path.
        """
        path_str = path.as_posix()
        result = await self.run(
            ["rev-parse", "--path-format=absolute", "--git-path", path_str],
            capture_output=True,
            cwd=cwd,
            deadline=deadline,
        )
        text = result.stdout.strip()
        if not text:
            msg = f"empty --git-path output for {path_str!r}"
            raise ValueError(msg)
        resolved = Path(text).expanduser()
        if not resolved.is_absolute():
            base = cwd if cwd is not None else self.root
            resolved = (base / resolved).resolve()
        else:
            resolved = resolved.resolve()
        return resolved

    async def branches(self, *, deadline: Deadline = NO_DEADLINE) -> frozenset[str]:
        """Return repository branch names.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        frozenset[str]
            A set of all (short) branch names in the repository.  Note that this only
            includes branches under `refs/heads/`, and not other refs like tags or
            remotes.

        """
        result = await self.run(
            ["for-each-ref", "--format=%(refname:short)", "refs/heads"],
            capture_output=True,
            deadline=deadline,
        )
        out = {line.strip() for line in result.stdout.splitlines()}
        out.discard("")  # remove empty lines if any
        return frozenset(out)

    @staticmethod
    async def default_branch(*, deadline: Deadline = NO_DEADLINE) -> str:
        """Return the default Git branch name.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        str
            The default branch name configured for this git installation.

        Raises
        ------
        ValueError
            If the default branch could not be determined from git output.
        """
        branch = await run(
            ["git", "var", "GIT_DEFAULT_BRANCH"],
            capture_output=True,
            deadline=deadline,
        )
        result = branch.stdout.strip()
        if not result:
            msg = "default Git branch name could not be determined"
            raise ValueError(msg)
        return result

    async def head_branch(self, *, deadline: Deadline = NO_DEADLINE) -> str | None:
        """Return the current HEAD branch.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        str | None
            The short branch name of the current HEAD, or None if HEAD is detached.

        Raises
        ------
        CommandError
            If Git returns an unexpected symbolic-ref failure.
        ValueError
            If we failed to parse the output or got an empty branch name.
        """
        # attached HEAD: try to read symbolic ref directly
        result = await self.run(
            ["symbolic-ref", "--quiet", "--short", "HEAD"],
            check=False,
            capture_output=True,
            deadline=deadline,
        )
        if result.returncode == 0:
            text = result.stdout.strip()
            if not text:
                msg = "empty symbolic-ref output for HEAD"
                raise ValueError(msg)
            return text
        if result.returncode != 1:
            raise CommandError(
                returncode=result.returncode,
                cmd=result.args,
                output=result.stdout,
                stderr=result.stderr,
            )

        # detached HEAD: let caller decide what to do
        return None

    @staticmethod
    async def supports_relative_paths(*, deadline: Deadline = NO_DEADLINE) -> bool:
        """Return whether this Git supports relative worktree paths.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        bool
            True if both `git worktree add` and `git worktree move` support
            `--relative-paths` according to their help output, false otherwise.
        """
        add_help = await run(
            ["git", "worktree", "add", "-h"],
            check=False,
            capture_output=True,
            deadline=deadline,
        )
        add_text = f"{add_help.stdout}\n{add_help.stderr}".lower()
        if add_help.returncode != 0 or "--relative-paths" not in add_text:
            return False
        move_help = await run(
            ["git", "worktree", "move", "-h"],
            check=False,
            capture_output=True,
            deadline=deadline,
        )
        move_text = f"{move_help.stdout}\n{move_help.stderr}".lower()
        return move_help.returncode == 0 and "--relative-paths" in move_text

    async def bare(self, *, deadline: Deadline = NO_DEADLINE) -> bool:
        """Return whether this repository is bare.

        Parameters
        ----------
        deadline : Deadline, optional
            An optional deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        bool
            True if this repository is a bare repository, false otherwise.

        Raises
        ------
        ValueError
            If we failed to parse the output.
        """
        result = await self.run(
            ["rev-parse", "--is-bare-repository"],
            capture_output=True,
            deadline=deadline,
        )
        value = result.stdout.strip().lower()
        if value == "true":
            return True
        if value == "false":
            return False
        msg = f"invalid --is-bare-repository output: {result.stdout!r}"
        raise ValueError(msg)

    async def worktrees(
        self,
        *,
        deadline: Deadline = NO_DEADLINE
    ) -> tuple[GitRepository.Worktree, ...]:
        """List all local worktrees for the given Git directory.

        Parameters
        ----------
        deadline : Deadline, optional
            An overall deadline by which the listing must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        tuple[GitRepository.Worktree, ...]
            A tuple of worktree entries.  Includes both attached (with branch) and
            detached (without branch) worktrees, which may be filtered by the caller as
            needed.
        """
        out: list[GitRepository.Worktree] = []
        path: Path | None = None
        branch: str | None = None
        result = await self.run(
            ["worktree", "list", "--porcelain"],
            capture_output=True,
            deadline=deadline,
        )
        for raw in result.stdout.splitlines():
            line = raw.strip()
            if not line:
                if path is not None:
                    out.append(self.Worktree(repo=self, path=path, branch=branch))
                path = None
                branch = None
                continue
            if line.startswith("worktree "):
                path = Path(line[len("worktree ") :]).expanduser().resolve()
                continue
            if line.startswith(f"branch {GIT_REF_HEADS_PREFIX}"):
                branch = line[len("branch ") + len(GIT_REF_HEADS_PREFIX) :]
        if path is not None:
            out.append(self.Worktree(repo=self, path=path, branch=branch))
        return tuple(out)

    async def get_worktree(
        self,
        branch: str,
        *,
        deadline: Deadline = NO_DEADLINE
    ) -> GitRepository.Worktree | None:
        """Return the worktree attached to the given branch, if any.

        Parameters
        ----------
        branch : str
            The short branch name to find a worktree for.
        deadline : Deadline, optional
            An overall deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        GitRepository.Worktree | None
            The worktree registered for the given branch, or None if no worktree is
            attached to that branch or if the attached worktree is out-of-repository.

        Raises
        ------
        OSError
            If multiple registered worktrees claim the given branch.
        """
        matches = [
            worktree
            for worktree in await self.worktrees(deadline=deadline)
            if worktree.branch == branch
        ]
        if not matches:
            return None
        if len(matches) > 1:
            paths = ", ".join(str(worktree.path) for worktree in matches)
            msg = f"multiple worktrees are attached to branch {branch!r}: {paths}"
            raise OSError(msg)
        return matches[0]

    async def head_worktree(
        self,
        *,
        deadline: Deadline = NO_DEADLINE
    ) -> GitRepository.Worktree | None:
        """Return the in-repository worktree attached to HEAD.

        Parameters
        ----------
        deadline : Deadline, optional
            An overall deadline by which this check must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        GitRepository.Worktree | None
            The worktree registered for the current HEAD branch, or None if HEAD is
            detached, unattached, or attached only to an out-of-repository worktree.
        """
        branch = await self.head_branch(deadline=deadline)
        if branch is None:
            return None
        return await self.get_worktree(branch, deadline=deadline)

    async def create_worktree(
        self,
        branch: str,
        target: Path | None = None,
        *,
        create_branch: bool = True,
        quiet: bool = False,
        deadline: Deadline = NO_DEADLINE,
    ) -> GitRepository.Worktree:
        """Create a new worktree for the given branch at the specified target path.

        Parameters
        ----------
        branch : str
            The short branch name to create a worktree for.
        target : Path | None, optional
            The target path to create the worktree at.  Must not already exist.
        create_branch : bool, optional
            If True (the default), then the branch will be created if it does not
            already exist.  If False, then the branch must already exist in the
            repository.
        quiet : bool, optional
            If True, then suppress any non-error output from the git command.  Default
            is False.
        deadline : Deadline, optional
            An overall deadline by which the creation must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.

        Returns
        -------
        GitRepository.Worktree
            A `Worktree` object representing the newly created worktree.

        Raises
        ------
        FileExistsError
            If the target path already exists.
        """
        if target is None:
            target = self.root / branch
        if target.exists():
            msg = "path already exists"
            raise FileExistsError(msg)
        target.parent.mkdir(parents=True, exist_ok=True)
        cmd = ["worktree", "add", "--relative-paths"]
        if create_branch:
            if branch not in await self.branches(deadline=deadline):
                cmd.extend(["-b", branch, str(target)])
            else:
                cmd.extend([str(target), branch])
        else:
            cmd.extend([str(target), branch])
        await self.run(cmd, capture_output=quiet, deadline=deadline)
        return GitRepository.Worktree(repo=self, path=target, branch=branch)

    async def _current_worktree_state(self, *, deadline: Deadline) -> dict[str, Path]:
        current: dict[str, Path] = {}
        for wt in await self.worktrees(deadline=deadline):
            if wt.branch is None:
                continue
            existing = current.setdefault(wt.branch, wt.path)
            if existing != wt.path:
                msg = (
                    f"multiple worktrees mapped to branch '{wt.branch}': {existing} "
                    f"and {wt.path}"
                )
                raise FileExistsError(msg)
        return current

    def _intended_worktree_changes(
        self,
        *,
        updates: Sequence[GitRefUpdate],
    ) -> tuple[list[str], list[str], list[tuple[str, str]]]:
        # get creation/destruction intent from transaction updates
        created_: dict[str, list[str]] = {}
        destroyed_: dict[str, list[str]] = {}
        created: list[str] = []
        destroyed: list[str] = []
        for update in updates:
            if update.created:
                created.append(update.branch)
                created_.setdefault(update.new, []).append(update.branch)
            elif update.destroyed:
                destroyed.append(update.branch)
                destroyed_.setdefault(update.old, []).append(update.branch)

        # infer rename hints from unambiguous create + destroy pairs on the same object
        renamed: list[tuple[str, str]] = []
        for oid in sorted(set(created_) & set(destroyed_)):
            c = created_[oid]
            d = destroyed_[oid]
            if len(c) == 1 and len(d) == 1:
                old_branch = d[0]
                new_branch = c[0]
                renamed.append((old_branch, new_branch))
                destroyed.remove(old_branch)
                created.remove(new_branch)

        return created, destroyed, renamed

    def _filter_worktree_conflicts(
        self,
        *,
        desired: dict[str, Path],
        current: dict[str, Path],
        created: list[str],
    ) -> dict[str, Path]:
        # sort branches by conflict priority, then filter out any whose slash-separated
        # paths would create a nested worktree conflicts
        winners: list[str] = []
        for branch in sorted(
            desired,
            key=lambda b: (
                0 if b in current else 1,  # prioritize existing
                0
                if b not in created
                else 1,  # ... then prioritize non-created branches
                b,  # ... then break ties lexically
            ),
        ):
            conflict: str | None = None
            for winner in winners:
                if branch == winner:
                    continue
                left_parts = branch.split("/")
                right_parts = winner.split("/")
                min_len = min(len(left_parts), len(right_parts))
                if left_parts[:min_len] == right_parts[:min_len]:
                    conflict = winner
                    break
            if conflict is None:
                winners.append(branch)
                continue
            warn(
                f"skipping branch '{branch}' due nested path conflict with "
                f"'{conflict}'"
            )

        return {branch: desired[branch] for branch in winners}

    async def _sync_create_worktree(
        self,
        *,
        current: dict[str, Path],
        branch: str,
        target: Path,
        create_branch: bool,
        deadline: Deadline,
    ) -> None:
        try:
            await self.create_worktree(
                branch,
                target=target,
                create_branch=create_branch,
                deadline=deadline,
            )
            current[branch] = target
        except _HOOK_OPERATION_ERRORS as err:
            warn(
                f"failed to create worktree for branch '{branch}' at {target}:\n{err}"
            )

    async def _sync_move_worktree(
        self,
        *,
        current: dict[str, Path],
        branch: str,
        source: Path,
        target: Path,
        old_branch: str | None = None,
        deadline: Deadline,
    ) -> None:
        try:
            worktree = GitRepository.Worktree(repo=self, path=source, branch=branch)
            await worktree.move(target=target, deadline=deadline)
            if old_branch is not None:
                current.pop(old_branch, None)
            current[branch] = target
        except _HOOK_OPERATION_ERRORS as err:
            warn(
                f"failed to move worktree for branch '{branch}' from {source} "
                f"to {target}:\n{err}"
            )

    async def _sync_destroy_worktree(
        self,
        *,
        current: dict[str, Path],
        branch: str,
        path: Path,
        deadline: Deadline,
    ) -> None:
        try:
            worktree = GitRepository.Worktree(repo=self, path=path, branch=branch)
            if await worktree.destroy(deadline=deadline):
                current.pop(branch, None)
        except _HOOK_OPERATION_ERRORS as err:
            warn(f"failed to destroy worktree for branch '{branch}' at {path}:\n{err}")

    async def sync_worktrees(
        self,
        updates: Sequence[GitRefUpdate] = (),
        *,
        deadline: Deadline = NO_DEADLINE,
    ) -> None:
        """Converge worktrees to the authoritative branch set.

        Parameters
        ----------
        updates : Sequence[GitRefUpdate], optional
            The parsed reference updates received from git on stdin, which will be used
            to derive explicit intent for branch creations and destructions, as well as
            implicit hints for branch renames where creation and destruction are paired
            on the same object.  If omitted, then convergence will transform directly
            from the current state to the desired state without any intent-based
            guidance.
        deadline : Deadline, optional
            An overall deadline by which the convergence must complete before raising a
            `TimeoutError`.  Defaults to an infinite deadline, which causes the command
            to block indefinitely until completion.  If the deadline is earlier than the
            time this method is called, a `TimeoutError` will be raised immediately.
        """
        # non-bare repositories are treated as single-worktree mode
        if not await self.bare():
            return

        # derive current and desired branch-to-path mappings
        current = await self._current_worktree_state(deadline=deadline)
        desired = {branch: (self.root / branch) for branch in await self.branches()}

        # derive explicit intent from transaction updates, preserving order
        created, destroyed, renamed = self._intended_worktree_changes(updates=updates)
        desired = self._filter_worktree_conflicts(
            desired=desired,
            current=current,
            created=created,
        )

        # apply rename hints first (when they map cleanly to current state)
        for old_branch, new_branch in renamed:
            source = current.get(old_branch)
            if source is None:
                continue
            target = desired.get(new_branch)
            if target is None or new_branch in current:
                continue
            await self._sync_move_worktree(
                current=current,
                branch=new_branch,
                source=source,
                target=target,
                old_branch=old_branch,
                deadline=deadline,
            )

        # apply explicit destroys for branches still present in current state
        for branch in destroyed:
            path = current.get(branch)
            if path is None or branch in desired:
                continue
            await self._sync_destroy_worktree(
                current=current,
                branch=branch,
                path=path,
                deadline=deadline,
            )

        # apply explicit creates for branches that are still missing
        for branch in created:
            if branch in current or branch not in desired:
                continue
            target = desired[branch]
            await self._sync_create_worktree(
                current=current,
                branch=branch,
                target=target,
                create_branch=True,
                deadline=deadline,
            )

        # remove branches no longer present in the repository
        stale = set(current) - set(desired)
        for branch in sorted(stale):
            path = current[branch]
            await self._sync_destroy_worktree(
                current=current,
                branch=branch,
                path=path,
                deadline=deadline
            )

        # move branches that are present but located at non-canonical paths
        shared = set(current) & set(desired)
        for branch in sorted(shared):
            source = current[branch]
            target = desired[branch]
            if source == target:
                continue
            await self._sync_move_worktree(
                current=current,
                branch=branch,
                source=source,
                target=target,
                deadline=deadline,
            )

        # create worktrees for branches that don't yet have one
        missing = set(desired) - set(current)
        for branch in sorted(missing):
            target = desired[branch]
            await self._sync_create_worktree(
                current=current,
                branch=branch,
                target=target,
                create_branch=False,
                deadline=deadline,
            )
